// Queue lives in workflow static data — no credentials, no database needed.
const store = $getWorkflowStaticData('global');
store.queue = store.queue || [];
store.recent = store.recent || [];
const b = $input.first().json.body || {};
if (b.probe === true) {
  // the site pings this before showing the request section — answer, queue nothing
  return [{ json: { success: true, probe: true, board: true } }];
}
const title = String(b.title || '').trim().slice(0, 120);
const artist = String(b.artist || '').trim().slice(0, 120);
const name = String(b.name || '').trim().slice(0, 60);
const note = String(b.note || '').trim().slice(0, 140);
if (!title) {
  return [{ json: { success: false, message: 'Tell us the song — a title is the one thing we need.' } }];
}
if (store.queue.length >= 50) {
  return [{ json: { success: false, message: 'The request box is full — give it a little while and try again.' } }];
}
const entry = { title, artist, name, note, at: new Date().toISOString() };
store.queue.push(entry);
store.recent.unshift(entry);
store.recent = store.recent.slice(0, 12);
return [{ json: { success: true, message: 'Request received — the studio reads every one.' } }];

// Drains the queue for the studio poller. Set your own secret below
// (and put the same value in macstudio-poller.sh) before activating.
const SECRET = 'CHANGE-ME-BEFORE-ACTIVATING';
const store = $getWorkflowStaticData('global');
const key = ($input.first().json.query || {}).key;
if (key !== SECRET || SECRET === 'CHANGE-ME-BEFORE-ACTIVATING') {
  return [{ json: { error: 'unauthorized' } }];
}
const out = store.queue || [];
store.queue = [];
return [{ json: { requests: out } }];

// Public, read-only: the last dozen requests for the site's jukebox wall.
const store = $getWorkflowStaticData('global');
const out = (store.recent || []).map(r => ({ title: r.title, artist: r.artist, name: r.name, note: r.note, at: r.at }));
return [{ json: { requests: out } }];
